import{_ as e,c as o,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"进阶: 高级特性与工作流 | oh-my-opencode","description":"掌握 oh-my-opencode 的高级特性。学习 AI 代理团队、并行任务、Categories/Skills 系统、生命周期钩子等核心功能，实现高效 AI 工作流编排。","frontmatter":{"title":"进阶: 高级特性与工作流 | oh-my-opencode","sidebarTitle":"像团队一样工作","subtitle":"进阶: 高级特性与工作流","description":"掌握 oh-my-opencode 的高级特性。学习 AI 代理团队、并行任务、Categories/Skills 系统、生命周期钩子等核心功能，实现高效 AI 工作流编排。","order":60},"headers":[],"relativePath":"zh/code-yeongyu/oh-my-opencode/advanced/index.md","filePath":"zh/code-yeongyu/oh-my-opencode/advanced/index.md"}'),r={name:"zh/code-yeongyu/oh-my-opencode/advanced/index.md"};function t(l,a,n,h,d,p){return s(),o("div",null,[...a[0]||(a[0]=[i(`<h1 id="进阶" tabindex="-1">进阶 <a class="header-anchor" href="#进阶" aria-label="Permalink to &quot;进阶&quot;">​</a></h1><p>本章节深入讲解 oh-my-opencode 的高级特性：专业 AI 代理团队、并行后台任务、Categories 和 Skills 系统、生命周期钩子等。掌握这些功能后，你将能够像管理真实团队一样编排 AI 工作流，实现更高效的开发体验。</p><h2 id="本章内容" tabindex="-1">本章内容 <a class="header-anchor" href="#本章内容" aria-label="Permalink to &quot;本章内容&quot;">​</a></h2><div class="grid-cards"><h3 id="ai-代理团队-10-位专家介绍" tabindex="-1"><a href="./ai-agents-overview/">AI 代理团队：10 位专家介绍</a> <a class="header-anchor" href="#ai-代理团队-10-位专家介绍" aria-label="Permalink to &quot;[AI 代理团队：10 位专家介绍](./ai-agents-overview/)&quot;">​</a></h3><p>全面介绍 10 个内置代理的功能、使用场景和调用方式。学会根据任务类型选择合适的代理，实现高效团队协作、并行任务执行与深度代码分析。</p><h3 id="prometheus-规划-面试式需求收集" tabindex="-1"><a href="./prometheus-planning/">Prometheus 规划：面试式需求收集</a> <a class="header-anchor" href="#prometheus-规划-面试式需求收集" aria-label="Permalink to &quot;[Prometheus 规划：面试式需求收集](./prometheus-planning/)&quot;">​</a></h3><p>通过面试模式明确需求并生成工作计划。Prometheus 会持续提问直到需求清晰，并自动咨询 Oracle、Metis、Momus 验证计划质量。</p><h3 id="后台并行任务-像团队一样工作" tabindex="-1"><a href="./background-tasks/">后台并行任务：像团队一样工作</a> <a class="header-anchor" href="#后台并行任务-像团队一样工作" aria-label="Permalink to &quot;[后台并行任务：像团队一样工作](./background-tasks/)&quot;">​</a></h3><p>深入讲解后台代理管理系统的使用方法。学会并发控制、任务轮询和结果获取，让多个 AI 代理同时处理不同任务，大幅提升工作效率。</p><h3 id="lsp-与-ast-grep-代码重构利器" tabindex="-1"><a href="./lsp-ast-tools/">LSP 与 AST-Grep：代码重构利器</a> <a class="header-anchor" href="#lsp-与-ast-grep-代码重构利器" aria-label="Permalink to &quot;[LSP 与 AST-Grep：代码重构利器](./lsp-ast-tools/)&quot;">​</a></h3><p>介绍 LSP 工具和 AST-Grep 工具的使用方法。展示如何实现 IDE 级别的代码分析和操作，包括符号导航、引用查找、结构化代码搜索。</p><h3 id="categories-和-skills-动态代理组合" tabindex="-1"><a href="./categories-skills/">Categories 和 Skills：动态代理组合</a> <a class="header-anchor" href="#categories-和-skills-动态代理组合" aria-label="Permalink to &quot;[Categories 和 Skills：动态代理组合](./categories-skills/)&quot;">​</a></h3><p>学会使用 Categories 和 Skills 系统创建专业化的子代理。实现灵活的代理组合，根据任务需求动态分配模型、工具和技能。</p><h3 id="内置-skills-浏览器自动化与-git-专家" tabindex="-1"><a href="./builtin-skills/">内置 Skills：浏览器自动化与 Git 专家</a> <a class="header-anchor" href="#内置-skills-浏览器自动化与-git-专家" aria-label="Permalink to &quot;[内置 Skills：浏览器自动化与 Git 专家](./builtin-skills/)&quot;">​</a></h3><p>详细介绍三个内置 Skills（playwright、frontend-ui-ux、git-master）的使用场景和最佳实践。快速接入浏览器自动化、前端 UI 设计、Git 操作等专业能力。</p><h3 id="生命周期钩子-自动化上下文与质量控制" tabindex="-1"><a href="./lifecycle-hooks/">生命周期钩子：自动化上下文与质量控制</a> <a class="header-anchor" href="#生命周期钩子-自动化上下文与质量控制" aria-label="Permalink to &quot;[生命周期钩子：自动化上下文与质量控制](./lifecycle-hooks/)&quot;">​</a></h3><p>介绍 32 个生命周期钩子的使用方法。理解如何自动化上下文注入、错误恢复和质量控制，构建完整的 AI 工作流自动化体系。</p><h3 id="斜杠命令-预设工作流" tabindex="-1"><a href="./slash-commands/">斜杠命令：预设工作流</a> <a class="header-anchor" href="#斜杠命令-预设工作流" aria-label="Permalink to &quot;[斜杠命令：预设工作流](./slash-commands/)&quot;">​</a></h3><p>介绍 6 个内置斜杠命令的使用方法。包括 /ralph-loop（快速修复循环）、/refactor（代码重构）、/start-work（启动项目执行）等常用工作流。</p><h3 id="配置深度定制-代理与权限管理" tabindex="-1"><a href="./advanced-configuration/">配置深度定制：代理与权限管理</a> <a class="header-anchor" href="#配置深度定制-代理与权限管理" aria-label="Permalink to &quot;[配置深度定制：代理与权限管理](./advanced-configuration/)&quot;">​</a></h3><p>教会用户深度自定义代理配置、权限设置、模型覆盖和提示词修改。掌握完整配置能力，打造符合团队规范的 AI 工作流。</p></div><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  第 1 步                  第 2 步                     第 3 步                          第 4 步                  │</span></span>
<span class="line"><span>│  了解 AI 代理团队    →   掌握规划与并行     →   学会动态代理组合     →   深度定制与自动化       │</span></span>
<span class="line"><span>│  (基础概念)               (核心能力)                 (高级用法)                   (专家级)                   │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>建议顺序</strong>：</p><ol><li><strong>先学 AI 代理团队</strong>：了解 10 个代理的职责和使用场景，这是理解整个系统的基石。</li><li><strong>再学规划与并行任务</strong>：掌握 Prometheus 规划和后台任务系统，这是高效协作的核心。</li><li><strong>接着学动态代理组合</strong>：学习 Categories 和 Skills，实现灵活的代理专业化。</li><li><strong>最后学深度定制</strong>：掌握生命周期钩子、斜杠命令和配置定制，打造完整工作流。</li></ol><p><strong>进阶路线</strong>：</p><ul><li>如果你的目标是<strong>快速上手</strong>：重点学习「AI 代理团队」和「斜杠命令」</li><li>如果你的目标是<strong>团队协作</strong>：深入学习「Prometheus 规划」和「后台并行任务」</li><li>如果你的目标是<strong>工作流自动化</strong>：学习「生命周期钩子」和「配置深度定制」</li></ul><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">开始前请确认</p><p>本章内容假设你已完成以下学习：</p><ul><li>✅ <a href="./../start/installation/">快速安装与配置</a>：已安装 oh-my-opencode 并配置至少一个 Provider</li><li>✅ <a href="./../start/sisyphus-orchestrator/">初识 Sisyphus：主编排器</a>：了解基本代理调用和委托机制</li><li>✅ <a href="./../platforms/provider-setup/">Provider 配置：Claude、OpenAI、Gemini</a>：已配置至少一个 AI Provider</li></ul></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章后，建议继续学习：</p><ul><li><strong><a href="./../faq/troubleshooting/">配置诊断与故障排除</a></strong>：遇到问题时快速定位和解决。</li><li><strong><a href="./../appendix/configuration-reference/">配置参考</a>：</strong> 查看完整的配置文件 schema，了解所有配置选项。</li><li><strong><a href="./../appendix/claude-code-compatibility/">Claude Code 兼容性</a>：</strong> 了解如何将现有 Claude Code 工作流迁移到 oh-my-opencode。</li></ul>`,15)])])}const g=e(r,[["render",t]]);export{u as __pageData,g as default};
